decimal totalFeedRecF = 0;
decimal totalFeedStockF = 0;
decimal sumWeightedValues = 0;
decimal sumWeights = 0;
decimal sumWeightedValuesMale = 0;
decimal sumWeightsMale = 0;
decimal dailyWeightedFemale = 0;
decimal dailyWeightsFemale = 0;
decimal dailyWeightedMale = 0;
decimal dailyWeightsMale = 0;
decimal totalFFeed = 0;
decimal totalMFeed = 0;
decimal totalFeedHatchEgg = 0;
private void xrTableCell56_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get values from fields
    decimal startMaleBirds = Convert.ToDecimal(GetCurrentColumnValue("StartMaleBirds") ?? 0);
    decimal startFemaleBirds = Convert.ToDecimal(GetCurrentColumnValue("StartFemaleBirds") ?? 0);

    // Calculate
    if (startFemaleBirds != 0) {
        decimal result = (startMaleBirds * 100) / startFemaleBirds;
        cell.Text = result.ToString("N2"); // 2 decimal places
        // Or: cell.Text = result.ToString("N0"); // whole number
    } else {
        cell.Text = "0.00";
    }
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      // Accumulate values
    object feedRecFObj = GetCurrentColumnValue("FeedRecF");
    object feedStockFObj = GetCurrentColumnValue("FeedStockF");

    if (feedRecFObj != null && feedRecFObj != DBNull.Value) {
        decimal.TryParse(feedRecFObj.ToString(), out decimal feedRecF);
        totalFeedRecF += feedRecF;
    }

    if (feedStockFObj != null && feedStockFObj != DBNull.Value) {
        decimal.TryParse(feedStockFObj.ToString(), out decimal feedStockF);
        totalFeedStockF += feedStockF;
    }

    //Lgoic for FeedBirdsWeekF
    // Get current row values
    object feedBirdsWeekFObj = GetCurrentColumnValue("FeedBirdsWeekF");
    object liveFemaleOpenObj = GetCurrentColumnValue("StartFemaleBirds");

    decimal feedBirdsWeekF = 0;
    decimal liveFemaleOpen = 0;

    // Parse FeedBirdsWeekF
    if (feedBirdsWeekFObj != null && feedBirdsWeekFObj != DBNull.Value) {
        decimal.TryParse(feedBirdsWeekFObj.ToString(), out feedBirdsWeekF);
    }

    // Parse LiveFemaleOpen (weight)
    if (liveFemaleOpenObj != null && liveFemaleOpenObj != DBNull.Value) {
        decimal.TryParse(liveFemaleOpenObj.ToString(), out liveFemaleOpen);
    }

    // Calculate weighted sum: value * weight
    sumWeightedValues += (feedBirdsWeekF * liveFemaleOpen);

    // Sum of weights
    sumWeights += liveFemaleOpen;

    //Lgoic for FeedBirdsWeekM
    object feedBirdsWeekMObj = GetCurrentColumnValue("FeedBirdsWeekM");
    object liveMaleOpenObj = GetCurrentColumnValue("StartFemaleBirds");

    decimal feedBirdsWeekM = 0;
    decimal liveMaleOpen = 0;

    if (feedBirdsWeekMObj != null && feedBirdsWeekMObj != DBNull.Value) {
        decimal.TryParse(feedBirdsWeekMObj.ToString(), out feedBirdsWeekM);
    }

    if (liveMaleOpenObj != null && liveMaleOpenObj != DBNull.Value) {
        decimal.TryParse(liveMaleOpenObj.ToString(), out liveMaleOpen);
    }

    sumWeightedValuesMale += (feedBirdsWeekM * liveMaleOpen);
    sumWeightsMale += liveMaleOpen;

        // FEMALE: FeedBirdsDayF weighted by LiveFemaleOpen
    object feedDayFObj = GetCurrentColumnValue("FeedBirdsDayF");
    object liveFemaleObj = GetCurrentColumnValue("StartFemaleBirds");

    decimal feedDayF = 0;
    decimal liveFemale = 0;

    if (feedDayFObj != null && feedDayFObj != DBNull.Value) {
        decimal.TryParse(feedDayFObj.ToString(), out feedDayF);
    }

    if (liveFemaleObj != null && liveFemaleObj != DBNull.Value) {
        decimal.TryParse(liveFemaleObj.ToString(), out liveFemale);
    }

    dailyWeightedFemale += (feedDayF * liveFemale);
    dailyWeightsFemale += liveFemale;

    // MALE: FeedBirdsDayM weighted by LiveMaleOpen
    object feedDayMObj = GetCurrentColumnValue("FeedBirdsDayM");
    object liveMaleObj = GetCurrentColumnValue("StartMaleBirds");

    decimal feedDayM = 0;
    decimal liveMale = 0;

    if (feedDayMObj != null && feedDayMObj != DBNull.Value) {
        decimal.TryParse(feedDayMObj.ToString(), out feedDayM);
    }

    if (liveMaleObj != null && liveMaleObj != DBNull.Value) {
        decimal.TryParse(liveMaleObj.ToString(), out liveMale);
    }

    dailyWeightedMale += (feedDayM * liveMale);
    dailyWeightsMale += liveMale;

    // Accumulate values for Cum H.E
    decimal.TryParse(GetCurrentColumnValue("FFeed")?.ToString() ?? "0", out decimal fFeed);
    decimal.TryParse(GetCurrentColumnValue("MFeed")?.ToString() ?? "0", out decimal mFeed);
    decimal.TryParse(GetCurrentColumnValue("FeedHatchEgg")?.ToString() ?? "0", out decimal hatchEgg);

    totalFFeed += fFeed;
    totalMFeed += mFeed;
    totalFeedHatchEgg += hatchEgg;

}

private void xrTableCell58_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Calculate sum of both
    decimal total = totalFeedRecF ;
    cell.Text = total.ToString("N0");
}

private void xrTableCell40_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Calculate weighted average: Σ(value * weight) / Σ(weights)
    if (sumWeights > 0) {
        decimal weightedAvg = sumWeightedValues / sumWeights;
        cell.Text = weightedAvg.ToString("N0"); // 2 decimal places
        // Or: cell.Text = weightedAvg.ToString("N3"); // 3 decimal places
    } else {
        cell.Text = "0";
    }

}

private void xrTableCell41_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       XRTableCell cell = sender as XRTableCell;
    cell.Text = sumWeightsMale > 0 ? 
        (sumWeightedValuesMale / sumWeightsMale).ToString("N0"): "0"; 
     }

private void xrTableCell42_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      XRTableCell cell = sender as XRTableCell;

    decimal totalWeights = sumWeights + sumWeightsMale;
    decimal totalWeightedValues = sumWeightedValues + sumWeightedValuesMale;

    cell.Text = totalWeights > 0 ? 
        (totalWeightedValues / totalWeights).ToString("N0"): "0";
}

private void xrTableCell43_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    if (dailyWeightsFemale > 0) {
        decimal weightedAvgFemale = dailyWeightedFemale / dailyWeightsFemale;
        cell.Text = weightedAvgFemale.ToString("N2");
    } else {
        cell.Text = "0.00";
    }
}

private void xrTableCell45_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    if (dailyWeightsMale > 0) {
        decimal weightedAvgMale = dailyWeightedMale / dailyWeightsMale;
        cell.Text = weightedAvgMale.ToString("N2");
    } else {
        cell.Text = "0.00";
    }

}

private void xrTableCell46_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Calculate totals
    decimal totalWeighted = dailyWeightedFemale + dailyWeightedMale;
    decimal totalWeights = dailyWeightsFemale + dailyWeightsMale;

    if (totalWeights > 0) {
        decimal weightedAvgTotal = totalWeighted / totalWeights;
        cell.Text = weightedAvgTotal.ToString("N2");
    } else {
        cell.Text = "0.00";
    }
}

private void xrTableCell71_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    if (totalFeedHatchEgg > 0) {
        decimal result = (totalFFeed + totalMFeed) / totalFeedHatchEgg;
        cell.Text = result.ToString("N0");
    } else {
        cell.Text = "0";
    }
}
